         {
             format = format.Replace(GigabyteSymbol, "GB");
             return output(Gigabytes);
         }

         if (has(MegabyteSymbol))
         {
             format = format.Replace(MegabyteSymbol, "MB");
             return output(Megabytes);
         }

         if (has(KilobyteSymbol))
         {
