/// <summary>
/// Gets the largest whole number value and its corresponding unit symbol.
/// </summary>
public string LargestWholeNumberSymbol => GetLargestWholeNumberParts().Symbol;

/// <summary>
/// Gets the value in the largest whole number unit.
/// </summary>
public double LargestWholeNumberValue => GetLargestWholeNumberParts().Value;

private (double Value, string Symbol) GetLargestWholeNumberParts()
{
    double bytes = Bytes;
    double abs = Math.Abs(bytes);

    if (abs >= BytesInTerabyte) return (bytes / BytesInTerabyte, TerabyteSymbol);
    if (abs >= BytesInGigabyte) return (bytes / BytesInGigabyte, GigabyteSymbol);
    if (abs >= BytesInMegabyte) return (bytes / BytesInMegabyte, MegabyteSymbol);
    if (abs >= BytesInKilobyte) return (bytes / BytesInKilobyte, KilobyteSymbol);
    if (abs >= 1) return (bytes, ByteSymbol);
    return (Bits, BitSymbol);
}

